"use client";

import { useId, useLayoutEffect } from "react";
import { useKeyboardRegistryContext } from "../providers/keyboard-context.js";

export interface UseScopeOptions {
  enabled?: boolean;
}

export function useScope(name: string | null, options: UseScopeOptions = {}): string | null {
  const { enabled = true } = options;
  const { pushScope } = useKeyboardRegistryContext();
  const order = useId();

  useLayoutEffect(() => {
    if (!enabled || name === null) return;
    return pushScope(name, order);
  }, [pushScope, name, enabled, order]);

  return enabled && name !== null ? name : null;
}

use-scope-basic.raw:
"use client";

import { KeyboardProvider, useKey, useScope } from "@diffgazer/keys";
import { useState } from "react";

function App() {
  const [modalOpen, setModalOpen] = useState(false);

  useKey("ctrl+k", () => setModalOpen(true));

  return (
    <div>
      <p>Press Ctrl+K to open the modal. The "ctrl+k" binding lives in the global scope.</p>
      {modalOpen && <Modal onClose={() => setModalOpen(false)} />}
    </div>
  );
}

function Modal({ onClose }: { onClose: () => void }) {
  const scope = useScope("modal");
  useKey("Escape", onClose, { scope });

  return (
    <div
      role="dialog"
      aria-label="Modal"
      style={{ marginTop: 8, padding: 12, border: "1px solid currentColor" }}
    >
      <p>Modal scope is active: Esc closes, Ctrl+K is suppressed.</p>
      <button type="button" onClick={onClose}>
        Close
      </button>
    </div>
  );
}

export default function UseScopeBasic() {
  return (
    <KeyboardProvider>
      <App />
    </KeyboardProvider>
  );
}

use-scope-nested.raw:
"use client";

import { KeyboardProvider, useKey, useScope } from "@diffgazer/keys";
import { useState } from "react";

function Page() {
  const [log, setLog] = useState("page");
  const [drawerOpen, setDrawerOpen] = useState(false);

  // Lives in the global scope; fires only while no deeper scope is active.
  useKey("Escape", () => setLog("page Escape"));

  return (
    <div>
      <p>Escape here logs from the page. Open the drawer to see a deeper scope win.</p>
      <button type="button" onClick={() => setDrawerOpen((open) => !open)}>
        {drawerOpen ? "Close drawer" : "Open drawer"}
      </button>
      {drawerOpen && <Drawer log={log} setLog={setLog} />}
    </div>
  );
}

function Drawer({ log, setLog }: { log: string; setLog: (v: string) => void }) {
  const [dialogOpen, setDialogOpen] = useState(false);
  const scope = useScope("drawer");

  useKey("Escape", () => setLog("drawer Escape"), { scope });

  return (
    <div style={{ marginTop: 8, padding: 12, border: "1px solid currentColor" }}>
      <p>Drawer scope active. Escape logs from the drawer, not the page.</p>
      <button type="button" onClick={() => setDialogOpen(true)}>
        Open dialog
      </button>
      {dialogOpen && <Dialog onClose={() => setDialogOpen(false)} setLog={setLog} />}
      <p>Last handler: {log}</p>
    </div>
  );
}

function Dialog({ onClose, setLog }: { onClose: () => void; setLog: (v: string) => void }) {
  const scope = useScope("dialog");

  // Deepest scope: Escape resolves here, shadowing drawer and page.
  useKey(
    "Escape",
    () => {
      setLog("dialog Escape");
      onClose();
    },
    { scope },
  );

  return (
    <div
      role="dialog"
      aria-label="Dialog"
      style={{ marginTop: 8, padding: 12, border: "1px solid currentColor" }}
    >
      <p>Dialog scope is deepest. Escape closes the dialog and yields back to the drawer.</p>
      <button type="button" onClick={onClose}>
        Close
      </button>
    </div>
  );
}

export default function UseScopeNested() {
  return (
    <KeyboardProvider>
      <Page />
    </KeyboardProvider>
  );
}
